/**
 * SQL safety layer for analytics queries.
 *
 * All queries generated by the LLM are validated here before execution:
 * - Only SELECT / WITH ... SELECT allowed
 * - DML / DDL keywords blocked
 * - Table whitelist enforced
 * - LIMIT 500 injected automatically if not present
 */

const MAX_QUERY_LENGTH = 4000
const MAX_LIMIT = 500

const ALLOWED_TABLES = new Set([
	"meal_forecasts",
	"meal_presences",
	"units",
	"mess_halls",
	"kitchen",
	"daily_menu",
	"menu_items",
	"recipes",
	"procurement_ata",
	"procurement_ata_item",
	"procurement_arp_item",
	"empenho",
	"product",
	"production_task",
	"meal_type",
	"recipe_ingredients",
	"v_meal_presences_with_user",
	"v_user_identity",
])

const BLOCKED_KEYWORDS = ["INSERT", "UPDATE", "DELETE", "DROP", "TRUNCATE", "ALTER", "COPY", "$$", "EXECUTE", "CALL"]

export function validateSql(sql: string): { valid: boolean; error?: string } {
	if (!sql?.trim()) return { valid: false, error: "SQL vazio" }

	const normalized = sql.trim().replace(/;$/, "")
	const up = normalized.toUpperCase()

	// Only SELECT or WITH … SELECT (CTEs)
	if (!up.startsWith("SELECT") && !up.startsWith("WITH")) {
		return { valid: false, error: "Apenas SELECT permitido" }
	}

	if (normalized.includes(";")) {
		return { valid: false, error: "Múltiplas instruções não são permitidas" }
	}

	// Block DML / DDL
	for (const kw of BLOCKED_KEYWORDS) {
		if (kw === "$$" ? up.includes(kw) : new RegExp(`\\b${kw}\\b`, "i").test(normalized)) {
			return { valid: false, error: `Keyword proibida: ${kw}` }
		}
	}

	const cteNames = new Set([...normalized.matchAll(/(?:WITH|,)\s*([a-zA-Z_][\w]*)\s+AS\s*\(/gi)].map((match) => match[1].toLowerCase()))

	// Enforce table whitelist via FROM / JOIN references
	const tableRefs = [...normalized.matchAll(/(?:FROM|JOIN)\s+("?[\w.]+"?)/gi)].map((match) => match[1].replace(/"/g, "").split(".").pop()?.toLowerCase() ?? "")
	for (const t of tableRefs) {
		if (!t || cteNames.has(t)) continue
		if (!ALLOWED_TABLES.has(t)) {
			return { valid: false, error: `Tabela não permitida: ${t}` }
		}
	}

	const limitMatches = [...normalized.matchAll(/\bLIMIT\s+(\d+)\b/gi)]
	for (const [, rawLimit] of limitMatches) {
		if (Number(rawLimit) > MAX_LIMIT) {
			return { valid: false, error: `LIMIT máximo permitido: ${MAX_LIMIT}` }
		}
	}

	if (normalized.length > MAX_QUERY_LENGTH) return { valid: false, error: "SQL muito longa" }

	return { valid: true }
}

export async function executeSql(sql: string): Promise<Record<string, unknown>[]> {
	// Inject LIMIT 500 if the query doesn't already have one
	const trimmedSql = sql.trim().replace(/;$/, "")
	const safeSql = /\bLIMIT\b/i.test(trimmedSql) ? trimmedSql : `${trimmedSql} LIMIT ${MAX_LIMIT}`

	const { getSupabaseServerClient } = await import("@/lib/supabase.server")
	const client = getSupabaseServerClient()

	const { data, error } = await client.rpc("execute_analytics_query", { query: safeSql })
	if (error) throw new Error(error.message)

	return Array.isArray(data) ? (data as Record<string, unknown>[]) : []
}
